pub trait SortUnstable {
	fn sort_unstable(&mut self);
}
impl SortUnstable for [i32; ARYSIZE] {
	fn sort_unstable(&mut self) {
		self.sort_unstable_by_key(|&x| (x == 0, x));
	}
}

